import { encodeImageFile } from '../chunk-X2ZYOJEA.js';

// src/steps/exif.ts
function exifStep() {
  return {
    name: "exif",
    shouldProcess: (file) => file.type.startsWith("image/"),
    async process(file, _context) {
      const processed = await encodeImageFile(file, {
        type: file.type || "image/jpeg",
        quality: 0.92,
        metadata: {
          originalSize: file.size,
          exifStripped: true
        }
      });
      if (!processed) return file;
      processed.metadata = {
        ...processed.metadata,
        processedSize: processed.size
      };
      return processed;
    }
  };
}

export { exifStep };
